Here are the public test cases for feature1_value_equality:
{
  "op": "value_equality",
  "description": "Loose structural equality between two credential-claim values that may each be a string, a string array, an object, or a null/undefined absence. Two strings are equal only when byte-for-byte identical (case sensitive). Two arrays are equal only when they have the same length and identical ordered elements. Two objects are equal when their case-insensitive serialized forms match. A string compared against a single-element array is equal when the string equals that one element. Any null or undefined operand makes the result not-equal, and two empty strings are treated as not-equal. Output is a single line 'equal=true' or 'equal=false'.",
  "cases": [
    {
      "input": {
        "left": null,
        "right": "somestring"
      },
      "expected_output": "equal=false\n"
    },
    {
      "input": {
        "left": "somestring",
        "right": "somestring"
      },
      "expected_output": "equal=true\n"
    },
    {
      "input": {
        "left": "somestring",
        "right": "Somestring"
      },
      "expected_output": "equal=false\n"
    },
    {
      "input": {
        "left": [
          "somestring1",
          "somestring2"
        ],
        "right": [
          "somestring1",
          "somestring2"
        ]
      },
      "expected_output": "equal=true\n"
    },
    {
      "input": {
        "left": [
          "somestring1"
        ],
        "right": "somestring1"
      },
      "expected_output": "equal=true\n"
    }
  ]
}

Here are the public test cases for feature2_audience_validation:
{
  "op": "audience_validation",
  "description": "Verify that the audience embedded in a decoded identity token matches the expected client identifier. When the token audience is a single string, it must exactly equal the expected value. When the token audience is an array of strings, it must equal the expected array element-for-element in order. Output is a single line 'match=true' or 'match=false'.",
  "cases": [
    {
      "input": {
        "token_aud": "banana",
        "expected_aud": "banana"
      },
      "expected_output": "match=true\n"
    },
    {
      "input": {
        "token_aud": "banana",
        "expected_aud": "bananammmm"
      },
      "expected_output": "match=false\n"
    },
    {
      "input": {
        "token_aud": [
          "banana",
          "apple",
          "https://nice.dom"
        ],
        "expected_aud": [
          "banana",
          "apple",
          "https://nice.dom"
        ]
      },
      "expected_output": "match=true\n"
    },
    {
      "input": {
        "token_aud": [
          "banana",
          "apple",
          "https://nice.dom"
        ],
        "expected_aud": [
          "ooo",
          "apple",
          "https://nice.dom"
        ]
      },
      "expected_output": "match=false\n"
    }
  ]
}

Here are the public test cases for feature3_1_token_expiration:
{
  "op": "token_expiration",
  "description": "Compute the absolute expiration instant of an identity token from its claim set. When the claims contain an 'exp' field (seconds since the Unix epoch, UTC), the output reports 'has_exp=true' followed by 'exp_utc=<ISO-8601 UTC timestamp>' derived from that value. When no 'exp' claim is present, no fixed instant exists; the output reports only 'has_exp=false'.",
  "cases": [
    {
      "input": {
        "claims": {}
      },
      "expected_output": "has_exp=false\n"
    },
    {
      "input": {
        "claims": {
          "exp": 123
        }
      },
      "expected_output": "has_exp=true\nexp_utc=1970-01-01T00:02:03.000Z\n"
    }
  ]
}

Here are the public test cases for feature3_2_jwt_segment_decode:
{
  "op": "jwt_segment_decode",
  "description": "Extract one of the three dot-separated segments (header, payload, or signature) from a compact three-part token string. With 'encoded' true the raw segment text is returned verbatim. With 'encoded' false the segment is base64url-decoded and parsed as JSON, yielding the structured object (UTF-8 / percent-decoding is applied so non-ASCII text is preserved). A token that is null, empty, contains no dot, or does not have exactly three parts is invalid and yields the empty object. Output is a single line 'value=<rendering>' where strings render as-is and objects render as compact JSON.",
  "cases": [
    {
      "input": {
        "segment": "header",
        "token": "abc.def.ghi",
        "encoded": true
      },
      "expected_output": "value=abc\n"
    },
    {
      "input": {
        "segment": "payload",
        "token": "abc.eyAidGV4dCIgOiAiSGVsbG8gV29ybGQgMTIzISJ9.ghi",
        "encoded": false
      },
      "expected_output": "value={\"text\":\"Hello World 123!\"}\n"
    },
    {
      "input": {
        "segment": "payload",
        "token": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJuYW1lIjoiSm9obiBEw7PDqyJ9.wMn-1oLWnxKJolMGb7YKnlwjqusWf4xnnjABgFaDkI4",
        "encoded": false
      },
      "expected_output": "value={\"name\":\"John Dóë\"}\n"
    },
    {
      "input": {
        "segment": "payload",
        "token": "testStringWithoutDots",
        "encoded": true
      },
      "expected_output": "value={}\n"
    }
  ]
}

Here are the public test cases for feature4_1_authorize_url:
{
  "op": "authorize_url",
  "description": "Build an authorization request URL from a base authorization endpoint and the client configuration. The endpoint's own pre-existing query (if any) is preserved, then the parameters client_id, redirect_uri, response_type, scope, nonce, and state are appended in that fixed order, followed by any extra custom request parameters in the order supplied. All keys and values are percent-encoded per application/x-www-form-urlencoded rules. Output is a single line 'url=<full url>'.",
  "cases": [
    {
      "input": {
        "config": {
          "client_id": "188968487735-b1hh7k87nkkh6vv84548sinju2kpr7gn.apps.googleusercontent.com",
          "response_type": "id_token token",
          "scope": "openid email profile"
        },
        "redirect_url": "https://localhost:44386",
        "nonce": "nonce",
        "state": "state",
        "authorization_endpoint": "http://example"
      },
      "expected_output": "url=http://example?client_id=188968487735-b1hh7k87nkkh6vv84548sinju2kpr7gn.apps.googleusercontent.com&redirect_uri=https%3A%2F%2Flocalhost%3A44386&response_type=id_token%20token&scope=openid%20email%20profile&nonce=nonce&state=state\n"
    },
    {
      "input": {
        "config": {
          "client_id": "myid",
          "response_type": "id_token token",
          "scope": "openid email profile"
        },
        "redirect_url": "https://localhost:44386",
        "nonce": "nonce",
        "state": "state",
        "authorization_endpoint": "https://login.microsoftonline.com/fabrikamb2c.onmicrosoft.com/oauth2/v2.0/authorize?p=b2c_1_sign_in"
      },
      "expected_output": "url=https://login.microsoftonline.com/fabrikamb2c.onmicrosoft.com/oauth2/v2.0/authorize?p=b2c_1_sign_in&client_id=myid&redirect_uri=https%3A%2F%2Flocalhost%3A44386&response_type=id_token%20token&scope=openid%20email%20profile&nonce=nonce&state=state\n"
    },
    {
      "input": {
        "config": {
          "client_id": "188968487735-b1hh7k87nkkh6vv84548sinju2kpr7gn.apps.googleusercontent.com",
          "response_type": "id_token token",
          "scope": "openid email profile"
        },
        "redirect_url": "https://localhost:44386",
        "nonce": "nonce",
        "state": "state",
        "authorization_endpoint": "http://example",
        "custom_request_params": {
          "t4": "ABC abc 123",
          "t3": "#",
          "t2": "-_.!~*()",
          "t1": ";,/?:@&=+$"
        }
      },
      "expected_output": "url=http://example?client_id=188968487735-b1hh7k87nkkh6vv84548sinju2kpr7gn.apps.googleusercontent.com&redirect_uri=https%3A%2F%2Flocalhost%3A44386&response_type=id_token%20token&scope=openid%20email%20profile&nonce=nonce&state=state&t4=ABC%20abc%20123&t3=%23&t2=-_.!~*()&t1=%3B%2C%2F%3F%3A%40%26%3D%2B%24\n"
    }
  ]
}

Here are the public test cases for feature4_2_end_session_url:
{
  "op": "end_session_url",
  "description": "Build an end-session (logout) URL from a base end-session endpoint, the identity-token hint, and the configured post-logout redirect URI. The endpoint's pre-existing query (if any) is preserved, then id_token_hint and post_logout_redirect_uri are appended in that fixed order, percent-encoded per application/x-www-form-urlencoded rules. Output is a single line 'url=<full url>'.",
  "cases": [
    {
      "input": {
        "config": {
          "post_logout_redirect_uri": "https://localhost:44386/Unauthorized"
        },
        "end_session_endpoint": "http://example",
        "id_token_hint": "mytoken"
      },
      "expected_output": "url=http://example?id_token_hint=mytoken&post_logout_redirect_uri=https%3A%2F%2Flocalhost%3A44386%2FUnauthorized\n"
    },
    {
      "input": {
        "config": {
          "post_logout_redirect_uri": "https://localhost:44386/Unauthorized"
        },
        "end_session_endpoint": "https://login.microsoftonline.com/fabrikamb2c.onmicrosoft.com/oauth2/v2.0/logout?p=b2c_1_sign_in",
        "id_token_hint": "UzI1NiIsImtpZCI6Il"
      },
      "expected_output": "url=https://login.microsoftonline.com/fabrikamb2c.onmicrosoft.com/oauth2/v2.0/logout?p=b2c_1_sign_in&id_token_hint=UzI1NiIsImtpZCI6Il&post_logout_redirect_uri=https%3A%2F%2Flocalhost%3A44386%2FUnauthorized\n"
    }
  ]
}

Here are the public test cases for feature5_callback_fragment_parse:
{
  "op": "callback_fragment_parse",
  "description": "Parse a redirect callback fragment of the form 'key1=value1&key2=value2&...' into its key/value map. Splitting is performed on '&' between pairs and on the first '=' within each pair, so any further '=' characters are kept inside the value (e.g. a base64 token ending in '==' or a state value that itself contains '='). Output prints one 'key=value' line per parsed entry in encounter order.",
  "cases": [
    {
      "input": {
        "fragment": "access_token=ACCESS-TOKEN&token_type=bearer&state=testState"
      },
      "expected_output": "access_token=ACCESS-TOKEN\ntoken_type=bearer\nstate=testState\n"
    },
    {
      "input": {
        "fragment": "access_token=ACCESS-TOKEN==&token_type=bearer&state=test=State"
      },
      "expected_output": "access_token=ACCESS-TOKEN==\ntoken_type=bearer\nstate=test=State\n"
    }
  ]
}

Here are the public test cases for feature7_platform_feature_gating:
{
  "op": "platform_feature_gating",
  "description": "Resolve whether the silent-renew and session-check features are enabled, given the requested configuration flags and the host platform. On an interactive browser platform the requested flags are honored as-is. On a non-interactive (server-side rendering) platform both features are forced off regardless of what was requested, because they depend on a live browser environment. Output is two lines: 'silent_renew=<true|false>' and 'start_checksession=<true|false>'.",
  "cases": [
    {
      "input": {
        "platform": "browser",
        "silent_renew": true,
        "start_checksession": true
      },
      "expected_output": "silent_renew=true\nstart_checksession=true\n"
    },
    {
      "input": {
        "platform": "server",
        "silent_renew": true,
        "start_checksession": true
      },
      "expected_output": "silent_renew=false\nstart_checksession=false\n"
    }
  ]
}
